import React, { Component } from "react";
// import { Link } from "gatsby"
import styled from "styled-components";
import styles from "../../styles/styles";

import HeroHeader from "../heroHeader/HeroHeader";
import TopNavBar from "../topNavBar/TopNavBar";
import MainContent from "../mainContent/MainContent";
import TopFooter from "../topFooter/TopFooter";
import BottomFooter from "../bottomFooter/BottomFooter";

const SuperWrapper = styled.div`
  // min-height: calc(100vh - var(--topNavBarHeight) - var(--topFooterHeight));
  // background: rgba(255,255,0,0.2);
`;

class WebPage extends Component {
  constructor() {
    super();

    this.state = {
      width: 0,
      height: 0,
      availHeight: 0,
      availWidth: 0,
      dpi: 0,
      displayRatio: 0,
      rendered: false,
    };

    this.updateDimensions = this.updateDimensions.bind(this);
  }

  updateDimensions() {
    // console.log("resize: " + this.state.width)

    this.setState({
      width: window.innerWidth,
      height: window.innerHeight,
      availWidth: window.screen.availWidth,
      availHeight: window.screen.availHeight,
      // DPI
      displayRatio: window.devicePixelRatio,
    });

    // console.log(this.state)

    // console.log(this.props.getDisplayData)

    if (this.props.getDisplayData !== undefined) {
      this.props.getDisplayData(this.state);
    }
    //

    // https://www.tutorialspoint.com/how-to-detect-the-screen-resolution-with-javascript
  }

  componentDidMount() {
    styles.SetCSSGlobals();

    window.addEventListener("resize", this.updateDimensions.bind(this));

    // Scroll because of hero header

    // console.log("Update scroll to: " + styles.variables.heroHeaderTotalHeight)

    // console.log(window.location.href)

    if (!window.location.href.includes("#")) {
      window.scrollTo(0, styles.variable.heroHeaderTotalHeight);
    }

    console.log("Webpage Did Mount");
    this.updateDimensions();
    // console.log("Webpage MN")
    // console.log(this.state)
  }

  useEffect() {
    console.log("Webpage Use Effect");
    this.updateDimensions();
  }

  componentDidUpdate() {
    console.log("Webpage Did Update");
    // this.updateDimensions()
  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.updateDimensions.bind(this));
  }

  render() {
    // console.log(this.state)

    // console.log(this.props.window)

    // var data = "1337"

    // console.log("Ratio: " + this.props.ratio)

    return (
      <SuperWrapper>
        <HeroHeader />

        <TopNavBar ww={this.state.width} />

        <MainContent>
          {this.props.children}

          {/*
            {React.cloneElement(this.props.children, { data: "hello" })}

          */}
        </MainContent>

        <TopFooter />

        <BottomFooter />
      </SuperWrapper>
    );
  }
}

//   {React.cloneElement(this.props.children, {displayRatio: this.state.displayRatio})}

// {React.cloneElement(this.props.children, { data: data })}

export default WebPage;
