import React, { Component } from "react";
// import { Link } from "gatsby"
import styled from "styled-components";
import styles from "../../styles/styles";

const PositionWrap = styled.div`
  ${styles.centerCol}
  padding-top: var(--topNavBarHeight);
  padding-bottom: var(--topFooterHeight);
  min-height: calc(100vh - var(--topNavBarHeight) - var(--topFooterHeight));
  // width: 100%;
  // background: rgba(255,255,0,0.2);
  ${(props) => props.outerStyle}
`;

const SizeWrap = styled.div`
  display: flex;
  flex-direction: row;

  padding-top: var(--top-article-padding);
  padding-bottom: var(--bottom-article-padding);

  ${styles.contentPageWidth}
  flex-grow: 1; // Make it fill entire parent element, like height: 100%;

  // background: rgba(0,255,255,0.4);

  ${(props) => (props.type === "article" ? "justify-content: center;" : "")}
`;

const ContentWrap = styled.article`
  display: flex;
  flex-direction: column;
  padding-left: var(--halfGutter);
  padding-right: var(--halfGutter);
  flex-grow: 1; // Make it fill entire parent element, like height: 100%;
  ${(props) => props.innerStyle}

  ${(props) => (props.type === "article" ? "max-Width: 640px;" : "")}
`;

class PageArticle extends Component {
  constructor() {
    super();
  }

  componentDidMount() {
    // console.log(styles.backgroundImage)

    console.log("Article Mounted");
  }

  render() {
    // console.log("Article Data: " + this.props.data)

    return (
      <PositionWrap
        outerStyle={this.props.outerStyle}
        className={this.props.outerClass}
      >
        <SizeWrap type={this.props.type}>
          <ContentWrap
            innerStyle={this.props.innerStyle}
            className={this.props.innerClass}
            type={this.props.type}
          >
            {this.props.children}

            {/*
              // Only works with a single children
              {React.cloneElement(this.props.children, { hello: "world" })}
            */}
          </ContentWrap>
        </SizeWrap>
      </PositionWrap>
    );
  }
}

// Article: {this.props.hello}

// {React.cloneElement(this.props.children, { hello: "world" })}

export default PageArticle;
